import random, itertools, math, numpy as np
def prob_tail(weights,p,ge=True):
    m=len(weights); ans=0
    for mask in range(1<<m):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i &1:
                s+=w; k+=1
        if s>=p-1e-12 if ge else s>p+1e-12:
            ans += (p**k)*((1-p)**(m-k))
    return ans
