def mu_D_and_influence(weights,t,r):
    m=len(weights); D=set()
    mu=0
    for mask in range(1<<m):
        s=sum(weights[i] for i in range(m) if mask>>i&1)
        k=mask.bit_count()
        if s < t - 1e-12:
            D.add(mask); mu += r**k*(1-r)**(m-k)
    I=0
    for i in range(m):
        prob=0
        for mask in range(1<<m):
            if mask>>i&1: continue
            in0 = mask in D
            in1 = (mask | (1<<i)) in D
            if in0 != in1:
                k=mask.bit_count()
                prob += r**k*(1-r)**(m-1-k)
        I += prob
    return mu,I
