import numpy as np, math
def compute_V(q,N=1000,iter=200):
    zgrid=np.linspace(0,1,N+1)
    V=np.where(zgrid<=0,1,np.where(zgrid>=1,0,1-zgrid)) # init
    p=1-q
    for it in range(iter):
        Vnew=V.copy()
        for idx,z in enumerate(zgrid[1:-1],1):
            best=0
            # stakes c in [0,1], but if fail remaining 1-c; c<=1-z? if c>1-z, fail impossible? then V=0
            for c in np.linspace(0,1,501):
                if c>=1: 
                    val=q*(1 if c>z else 0) + p*0
                else:
                    if c>z:
                        vs=1
                    else:
                        zs=(z-c)/(1-c)
                        vs=np.interp(zs,zgrid,V)
                    zf=z/(1-c)
                    vf=0 if zf>=1 else np.interp(zf,zgrid,V)
                    val=q*vs+p*vf
                if val>best: best=val
            Vnew[idx]=best
        V=Vnew
    return zgrid,V
